     1→import React from 'react';
     2→import { Recommendation, GeneratedSolution } from '../types';
     3→import { Zap, Clock, TrendingUp, CheckCircle2, Eye, ArrowRight, Fuel } from 'lucide-react';
     4→
     5→interface Props {
     6→  rec: Recommendation;
     7→  cost: number;
     8→  onApply: (rec: Recommendation) => void;
     9→  existingSolution?: GeneratedSolution;
    10→  onView: (solution: GeneratedSolution) => void;
    11→}
    12→
    13→const RecommendationCard: React.FC<Props> = ({ rec, cost, onApply, existingSolution, onView }) => {
    14→  const isCritical = rec.priority === 'critical';
    15→  
    16→  // Style configurations based on priority (matching the image)
    17→  const styles = isCritical 
    18→    ? {
    19→        wrapper: 'bg-[#180505] border-red-500/20 hover:border-red-500/40',
    20→        badge: 'bg-red-600 text-white',
    21→        text: 'text-red-500',
    22→        impactDot: 'bg-[#10b981]', // Green dots as per image
    23→        impactDotEmpty: 'bg-[#1e293b]'
    24→      }
    25→    : {
    26→        wrapper: 'bg-[#180e05] border-orange-500/20 hover:border-orange-500/40',
    27→        badge: 'bg-orange-500 text-white',
    28→        text: 'text-orange-500',
    29→        impactDot: 'bg-[#10b981]',
    30→        impactDotEmpty: 'bg-[#1e293b]'
    31→      };
    32→
    33→  // Convert impact string 'High'/'Medium'/'Low' to a number 1-5 for the dots
    34→  const getImpactScore = (impact: string) => {
    35→    switch(impact.toLowerCase()) {
    36→      case 'high': return 5;
    37→      case 'medium': return 3;
    38→      default: return 1;
    39→    }
    40→  };
    41→
    42→  const impactScore = getImpactScore(rec.impact);
    43→
    44→  return (
    45→    <div className={`p-6 rounded-2xl border transition-all group relative flex flex-col h-full ${styles.wrapper}`}>
    46→      
    47→      {/* Header: Badges & Impact */}
    48→      <div className="flex justify-between items-start mb-4">
    49→        <div className="flex items-center gap-3">
    50→          {/* Priority Badge */}
    51→          <span className={`px-2.5 py-1 rounded-md text-[10px] font-bold uppercase tracking-wider ${styles.badge}`}>
    52→            {rec.priority}
    53→          </span>
    54→          {/* Category Badge */}
