    26→    }
    27→    return updated;
    28→  },
    29→
    30→  update: (index: number, updatedData: Partial<AnalysisResult>) => {
    31→    const current = db.getAll();
    32→    if (current[index]) {
    33→      current[index] = { ...current[index], ...updatedData };
